"use strict";
const pptxgen = require("pptxgenjs");

// ─── PALETTE ────────────────────────────────────────────────────────────────
const C = {
  darkBg:   "0F172A",
  navyMid:  "1E3A5F",
  accent:   "0EA5E9",   // sky blue
  accentLt: "BAE6FD",   // light sky
  white:    "FFFFFF",
  lightBg:  "F0F7FF",
  cardBg:   "FFFFFF",
  textDark: "1E293B",
  textMid:  "334155",
  textMuted:"64748B",
  red:      "EF4444",
  yellow:   "F59E0B",
  green:    "10B981",
  border:   "E2E8F0",
};

// Shadow factory – must return fresh object each call
const makeShadow = () => ({
  type: "outer", color: "000000", blur: 8, offset: 2, angle: 135, opacity: 0.10
});

// ─── PRESENTATION ────────────────────────────────────────────────────────────
let pres = new pptxgen();
pres.layout = "LAYOUT_16x9";  // 10" × 5.625"
pres.author = "SEO Team";
pres.title  = "SEO Audit Report";

// ═══════════════════════════════════════════════════════════════════════════
// SLIDE 1 – TITLE
// ═══════════════════════════════════════════════════════════════════════════
{
  let s = pres.addSlide();
  s.background = { color: C.darkBg };

  // Left accent bar
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0, y: 0, w: 0.18, h: 5.625, fill: { color: C.accent }, line: { color: C.accent }
  });

  // Decorative circle (top-right)
  s.addShape(pres.shapes.OVAL, {
    x: 7.8, y: -1.5, w: 4.5, h: 4.5,
    fill: { color: C.navyMid, transparency: 40 }, line: { color: C.navyMid, transparency: 40 }
  });
  s.addShape(pres.shapes.OVAL, {
    x: 8.5, y: -0.8, w: 3, h: 3,
    fill: { color: C.accent, transparency: 80 }, line: { color: C.accent, transparency: 80 }
  });

  // Tag line
  s.addText("WEBSITE PERFORMANCE ANALYSIS", {
    x: 0.45, y: 1.2, w: 7, h: 0.35,
    fontSize: 9, fontFace: "Trebuchet MS", color: C.accent,
    charSpacing: 4, bold: true, margin: 0
  });

  // Main title
  s.addText("SEO Audit Report", {
    x: 0.45, y: 1.65, w: 7.5, h: 1.4,
    fontSize: 48, fontFace: "Trebuchet MS", color: C.white, bold: true, margin: 0
  });

  // Subtitle
  s.addText("Comprehensive analysis of technical health, on-page performance,\nkeyword rankings, and growth opportunities.", {
    x: 0.45, y: 3.15, w: 7, h: 0.9,
    fontSize: 13, fontFace: "Calibri", color: C.accentLt, margin: 0
  });

  // Date + version
  s.addText("Q2 2026  |  Prepared by SEO Team  |  Confidential", {
    x: 0.45, y: 4.8, w: 9, h: 0.4,
    fontSize: 9, fontFace: "Calibri", color: C.textMuted, margin: 0
  });
}

// ═══════════════════════════════════════════════════════════════════════════
// SLIDE 2 – EXECUTIVE SUMMARY (4 KPI cards)
// ═══════════════════════════════════════════════════════════════════════════
{
  let s = pres.addSlide();
  s.background = { color: C.lightBg };

  // Header bar
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0, y: 0, w: 10, h: 0.72, fill: { color: C.darkBg }, line: { color: C.darkBg }
  });
  s.addText("EXECUTIVE SUMMARY", {
    x: 0.4, y: 0, w: 9, h: 0.72,
    fontSize: 14, fontFace: "Trebuchet MS", color: C.white, bold: true, valign: "middle", margin: 0
  });

  // Intro text
  s.addText("This audit covers four core SEO dimensions. Scores reflect current performance benchmarked against industry standards.", {
    x: 0.4, y: 0.85, w: 9.2, h: 0.45,
    fontSize: 11, fontFace: "Calibri", color: C.textMid, margin: 0
  });

  // KPI cards data
  const kpis = [
    { label: "Overall SEO Score",  value: "62",  unit: "/100", color: C.yellow, note: "Needs Improvement" },
    { label: "Organic Traffic",    value: "+18", unit: "%",    color: C.green,  note: "YoY Growth" },
    { label: "Critical Issues",    value: "23",  unit: "",     color: C.red,    note: "High Priority Fixes" },
    { label: "Indexable Pages",    value: "84",  unit: "%",    color: C.accent, note: "Of Total URLs" },
  ];

  kpis.forEach((k, i) => {
    const x = 0.3 + i * 2.38;
    const y = 1.45;
    const w = 2.1;
    const h = 2.6;

    // Card background
    s.addShape(pres.shapes.RECTANGLE, {
      x, y, w, h,
      fill: { color: C.cardBg }, line: { color: C.border, pt: 1 },
      shadow: makeShadow()
    });
    // Top accent bar
    s.addShape(pres.shapes.RECTANGLE, {
      x, y, w, h: 0.08, fill: { color: k.color }, line: { color: k.color }
    });
    // Label
    s.addText(k.label, {
      x: x + 0.12, y: y + 0.18, w: w - 0.24, h: 0.5,
      fontSize: 10, fontFace: "Calibri", color: C.textMuted, bold: true, margin: 0
    });
    // Big number
    s.addText(k.value + k.unit, {
      x: x + 0.08, y: y + 0.65, w: w - 0.16, h: 1.1,
      fontSize: 46, fontFace: "Trebuchet MS", color: k.color, bold: true, align: "center", margin: 0
    });
    // Note
    s.addShape(pres.shapes.RECTANGLE, {
      x: x + 0.15, y: y + 1.85, w: w - 0.30, h: 0.35,
      fill: { color: k.color, transparency: 85 }, line: { color: k.color, transparency: 85 }
    });
    s.addText(k.note, {
      x: x + 0.15, y: y + 1.85, w: w - 0.30, h: 0.35,
      fontSize: 9, fontFace: "Calibri", color: k.color, bold: true, align: "center", valign: "middle", margin: 0
    });
  });

  // Summary bullets
  s.addText([
    { text: "Top priority: fix 23 critical technical errors blocking crawl & indexation", options: { bullet: true, breakLine: true, color: C.textDark } },
    { text: "Keyword rankings improving — 18% more organic sessions YoY despite indexation gaps", options: { bullet: true, breakLine: true, color: C.textDark } },
    { text: "84% of pages are indexable; 16% blocked by noindex, robots.txt, or redirects", options: { bullet: true, color: C.textDark } },
  ], {
    x: 0.4, y: 4.15, w: 9.2, h: 1.1,
    fontSize: 10.5, fontFace: "Calibri", color: C.textDark, margin: 0
  });
}

// ═══════════════════════════════════════════════════════════════════════════
// SLIDE 3 – TECHNICAL SEO HEALTH (grid of checks)
// ═══════════════════════════════════════════════════════════════════════════
{
  let s = pres.addSlide();
  s.background = { color: C.lightBg };

  // Header
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0, y: 0, w: 10, h: 0.72, fill: { color: C.darkBg }, line: { color: C.darkBg }
  });
  s.addText("TECHNICAL SEO HEALTH", {
    x: 0.4, y: 0, w: 9, h: 0.72,
    fontSize: 14, fontFace: "Trebuchet MS", color: C.white, bold: true, valign: "middle", margin: 0
  });
  s.addText("Crawl & Indexation  |  Site Architecture  |  Speed & Security", {
    x: 6, y: 0, w: 3.8, h: 0.72,
    fontSize: 9, fontFace: "Calibri", color: C.accentLt, valign: "middle", align: "right", margin: 0
  });

  const checks = [
    { label: "HTTPS / SSL",             status: "PASS",  detail: "Valid certificate, no mixed-content" },
    { label: "XML Sitemap",             status: "WARN",  detail: "Sitemap found but contains 41 blocked URLs" },
    { label: "Robots.txt",              status: "WARN",  detail: "Blocking 3 crawlable revenue sections" },
    { label: "Crawl Depth",             status: "PASS",  detail: "90% of pages reachable in ≤ 3 clicks" },
    { label: "Canonical Tags",          status: "FAIL",  detail: "Missing on 218 product pages" },
    { label: "Structured Data",         status: "WARN",  detail: "Schema errors on 57 pages (Product, FAQPage)" },
    { label: "Mobile-Friendly",         status: "PASS",  detail: "All pages pass Mobile-Friendly Test" },
    { label: "Core Web Vitals (field)", status: "FAIL",  detail: "LCP & INP fail on mobile (Google data)" },
    { label: "Hreflang Tags",           status: "WARN",  detail: "Missing return tags on 12 locale pairs" },
    { label: "Redirect Chains",         status: "FAIL",  detail: "34 chains of 3+ hops found" },
    { label: "Internal Linking",        status: "PASS",  detail: "Healthy link distribution across key pages" },
    { label: "Broken Links (4xx)",      status: "FAIL",  detail: "89 broken internal links detected" },
  ];

  const statusColor = { PASS: C.green, WARN: C.yellow, FAIL: C.red };
  const cols = 2, rows = 6;
  const cardW = 4.5, cardH = 0.62, gapX = 0.45, startX = 0.27, startY = 0.9;

  checks.forEach((c, i) => {
    const col = i % cols;
    const row = Math.floor(i / cols);
    const x = startX + col * (cardW + gapX);
    const y = startY + row * (cardH + 0.06);
    const sc = statusColor[c.status];

    s.addShape(pres.shapes.RECTANGLE, {
      x, y, w: cardW, h: cardH,
      fill: { color: C.cardBg }, line: { color: C.border, pt: 1 }
    });
    // Left status stripe
    s.addShape(pres.shapes.RECTANGLE, {
      x, y, w: 0.07, h: cardH, fill: { color: sc }, line: { color: sc }
