"use strict";
const pptxgen = require("pptxgenjs");

// ─── PALETTE ────────────────────────────────────────────────────────────────
const C = {
  darkBg:   "0F172A",
  navyMid:  "1E3A5F",
  accent:   "0EA5E9",   // sky blue
  accentLt: "BAE6FD",   // light sky
  white:    "FFFFFF",
  lightBg:  "F0F7FF",
  cardBg:   "FFFFFF",
  textDark: "1E293B",
  textMid:  "334155",
  textMuted:"64748B",
  red:      "EF4444",
  yellow:   "F59E0B",
  green:    "10B981",
  border:   "E2E8F0",
};

// Shadow factory – must return fresh object each call
const makeShadow = () => ({
  type: "outer", color: "000000", blur: 8, offset: 2, angle: 135, opacity: 0.10
});

// ─── PRESENTATION ────────────────────────────────────────────────────────────
let pres = new pptxgen();
pres.layout = "LAYOUT_16x9";  // 10" × 5.625"
pres.author = "SEO Team";
pres.title  = "SEO Audit Report";

// ═══════════════════════════════════════════════════════════════════════════
// SLIDE 1 – TITLE
// ═══════════════════════════════════════════════════════════════════════════
{
