  });
  s.addText(title, {
    x: 0.42, y: 0, w: sub ? 6.5 : 9.4, h: 0.72,
    fontSize: 14, fontFace: "Trebuchet MS", color: C.white, bold: true, valign: "middle", margin: 0
  });
  if (sub) {
    s.addText(sub, {
      x: 6.8, y: 0, w: 3.0, h: 0.72,
      fontSize: 8.5, fontFace: "Calibri", color: C.accentLt, valign: "middle", align: "right", margin: 0
    });
  }
  // Footer discreta agencia
  s.addText("GORMARAN Marketing Agency  ·  gormaran-marketing.com", {
    x: 0, y: 5.38, w: 10, h: 0.245,
    fontSize: 7, fontFace: "Calibri", color: C.textMuted, align: "right", margin: 0
