    { label: "HTTPS / Certificado SSL",          status: "OK",   detail: "Certificado válido, sin contenido mixto detectado" },
    { label: "Sitemap XML",                       status: "WARN", detail: "Sitemap encontrado pero incluye 38 URLs bloqueadas" },
    { label: "Robots.txt",                        status: "WARN", detail: "Bloquea 2 secciones con páginas de venta directa" },
    { label: "Profundidad de rastreo",            status: "OK",   detail: "88% de páginas accesibles en ≤ 3 clics" },
    { label: "Etiquetas Canonical",               status: "FAIL", detail: "Ausentes en 196 páginas de producto y añada" },
    { label: "Datos Estructurados (Schema)",      status: "WARN", detail: "Errores de Schema en 63 páginas (Product, LocalBusiness)" },
    { label: "Adaptación móvil",                  status: "OK",   detail: "Supera el test de compatibilidad móvil de Google" },
    { label: "Core Web Vitals (datos de campo)",  status: "FAIL", detail: "LCP e INP suspenden en móvil según GSC" },
    { label: "Hreflang (ES / EN / DE / FR)",      status: "WARN", detail: "Faltan etiquetas de retorno en 16 pares de idioma" },
    { label: "Cadenas de redirección",            status: "FAIL", detail: "29 cadenas de 3+ saltos detectadas" },
    { label: "Enlazado interno",                  status: "OK",   detail: "Distribución de autoridad aceptable entre páginas clave" },
    { label: "Errores 4xx (enlaces rotos)",       status: "FAIL", detail: "76 enlaces internos rotos detectados" },
  ];

  const statusColor = { OK: C.green, WARN: C.yellow, FAIL: C.red };
  const statusLabel = { OK: "OK", WARN: "AVISO", FAIL: "ERROR" };
  const cols = 2, cardW = 4.5, cardH = 0.62, gapX = 0.45, startX = 0.27, startY = 0.88;

  checks.forEach((c, i) => {
    const col = i % cols;
    const row = Math.floor(i / cols);
    const x = startX + col * (cardW + gapX);
    const y = startY + row * (cardH + 0.055);
    const sc = statusColor[c.status];

    s.addShape(pres.shapes.RECTANGLE, {
      x, y, w: cardW, h: cardH,
      fill: { color: C.cardBg }, line: { color: C.border, pt: 1 }
    });
    s.addShape(pres.shapes.RECTANGLE, {
      x, y, w: 0.07, h: cardH, fill: { color: sc }, line: { color: sc }
    });
    s.addShape(pres.shapes.RECTANGLE, {
      x: x + cardW - 0.88, y: y + 0.14, w: 0.74, h: 0.27,
      fill: { color: sc, transparency: 85 }, line: { color: sc, transparency: 50 }
    });
    s.addText(statusLabel[c.status], {
      x: x + cardW - 0.88, y: y + 0.14, w: 0.74, h: 0.27,
      fontSize: 7, fontFace: "Trebuchet MS", color: sc, bold: true, align: "center", valign: "middle", margin: 0
    });
    s.addText(c.label, {
      x: x + 0.15, y: y + 0.07, w: cardW - 1.1, h: 0.28,
      fontSize: 9.5, fontFace: "Trebuchet MS", color: C.textDark, bold: true, margin: 0
    });
    s.addText(c.detail, {
      x: x + 0.15, y: y + 0.33, w: cardW - 1.1, h: 0.24,
      fontSize: 8.5, fontFace: "Calibri", color: C.textMuted, margin: 0
    });
  });

  // Leyenda
  [["OK", C.green], ["AVISO", C.yellow], ["ERROR", C.red]].forEach(([st, sc], i) => {
    const lx = 0.35 + i * 1.4;
    s.addShape(pres.shapes.RECTANGLE, {
      x: lx, y: 5.2, w: 0.16, h: 0.16,
      fill: { color: sc }, line: { color: sc }
    });
    s.addText(st, {
      x: lx + 0.22, y: 5.17, w: 1.0, h: 0.22,
      fontSize: 8.5, fontFace: "Calibri", color: C.textMuted, bold: true, margin: 0
    });
  });
}

